### 3.3 핵심 컴포넌트

**PushNotificationService 인터페이스**

```kotlin
// notification-service/src/main/kotlin/com/maum/notification/push/PushNotificationService.kt

interface PushNotificationService {
    suspend fun send(request: PushRequest): PushResult
    suspend fun sendBatch(requests: List<PushRequest>): List<PushResult>
}

data class PushRequest(
    val deviceToken: String,
    val platform: DevicePlatform,
    val title: String,
    val body: String,
    val data: Map<String, String> = emptyMap(),
    val notificationType: NotificationType,
    val priority: PushPriority = PushPriority.NORMAL  // HIGH: 통화 알림
)

enum class PushPriority { HIGH, NORMAL }

sealed class PushResult {
    data class Success(val messageId: String) : PushResult()
    data class InvalidToken(val token: String) : PushResult()
    data class Failure(val error: String, val retryable: Boolean) : PushResult()
}
```

**APNs 클라이언트 구현체 (iOS)**

```kotlin
// notification-service/src/main/kotlin/com/maum/notification/push/apns/ApnsClient.kt

@Component
class ApnsClient(
    private val httpClient: HttpClient,
    @Value("\${push.apns.key-id}") private val keyId: String,
    @Value("\${push.apns.team-id}") private val teamId: String,
    @Value("\${push.apns.bundle-id}") private val bundleId: String,
    @Value("\${push.apns.private-key-path}") private val privateKeyPath: String,
    @Value("\${push.apns.production:false}") private val isProduction: Boolean,
) : PushNotificationService {

    private val baseUrl = if (isProduction)
        "https://api.push.apple.com"
    else
        "https://api.sandbox.push.apple.com"

    // JWT 토큰 캐싱 (APNs 요구사항: 1시간 이내 재사용 가능)
    private var cachedJwt: String? = null
    private var jwtCreatedAt: Instant = Instant.EPOCH

    override suspend fun send(request: PushRequest): PushResult {
        val jwt = getOrRefreshJwt()
        val apnsId = UUID.randomUUID().toString()

        val payload = buildApnsPayload(request)

        val response = httpClient.post("$baseUrl/3/device/${request.deviceToken}") {
            header("authorization", "bearer $jwt")
            header("apns-topic", bundleId)
            header("apns-push-type", if (request.priority == PushPriority.HIGH) "alert" else "alert")
            header("apns-priority", if (request.priority == PushPriority.HIGH) "10" else "5")
            header("apns-id", apnsId)
            contentType(ContentType.Application.Json)
            setBody(payload)
        }

        return when (response.status.value) {
            200 -> PushResult.Success(apnsId)
            400 -> {
                val error = response.body<ApnsErrorResponse>()
                if (error.reason == "BadDeviceToken" || error.reason == "Unregistered") {
                    PushResult.InvalidToken(request.deviceToken)
                } else {
                    PushResult.Failure(error.reason, retryable = false)
                }
            }
            429, 500, 503 -> PushResult.Failure("APNs 일시 장애: ${response.status}", retryable = true)
            else -> PushResult.Failure("Unknown: ${response.status}", retryable = false)
        }
    }

    override suspend fun sendBatch(requests: List<PushRequest>): List<PushResult> =
        requests.map { send(it) }

    private fun getOrRefreshJwt(): String {
        val now = Instant.now()
        // JWT는 55분마다 갱신 (APNs: 1시간 유효)
        if (cachedJwt != null && Duration.between(jwtCreatedAt, now).toMinutes() < 55) {
            return cachedJwt!!
        }

        val privateKey = loadPrivateKey(privateKeyPath)
        val jwt = Jwts.builder()
            .setHeaderParam("kid", keyId)
            .setIssuer(teamId)
            .setIssuedAt(Date.from(now))
            .signWith(privateKey, SignatureAlgorithm.ES256)
            .compact()

        cachedJwt = jwt
        jwtCreatedAt = now
        return jwt
    }

    private fun buildApnsPayload(request: PushRequest): Map<String, Any> = mapOf(
        "aps" to mapOf(
            "alert" to mapOf("title" to request.title, "body" to request.body),
            "sound" to "default",
            "badge" to 1,
            "content-available" to if (request.priority == PushPriority.HIGH) 1 else 0
        )
    ) + request.data

    private fun loadPrivateKey(path: String): PrivateKey {
        // .p8 파일에서 EC 개인키 로드
        val keyBytes = File(path).readBytes()
        val keyFactory = KeyFactory.getInstance("EC")
        return keyFactory.generatePrivate(PKCS8EncodedKeySpec(keyBytes))
    }
}

data class ApnsErrorResponse(val reason: String, val timestamp: Long? = null)
```

**FCM HTTP v1 API 클라이언트 구현체 (Android)**

```kotlin
// notification-service/src/main/kotlin/com/maum/notification/push/fcm/FcmHttpClient.kt

@Component
class FcmHttpClient(
    private val httpClient: HttpClient,
    @Value("\${push.fcm.project-id}") private val projectId: String,
    @Value("\${push.fcm.service-account-key-path}") private val serviceAccountKeyPath: String,
) : PushNotificationService {

    private val fcmUrl = "https://fcm.googleapis.com/v1/projects/$projectId/messages:send"

    // OAuth2 액세스 토큰 캐싱
    private var cachedAccessToken: String? = null
    private var tokenExpiresAt: Instant = Instant.EPOCH

    override suspend fun send(request: PushRequest): PushResult {
        val accessToken = getOrRefreshAccessToken()

        val fcmMessage = buildFcmMessage(request)

        val response = httpClient.post(fcmUrl) {
            header("Authorization", "Bearer $accessToken")
            contentType(ContentType.Application.Json)
            setBody(mapOf("message" to fcmMessage))
        }

        return when (response.status.value) {
            200 -> {
                val body = response.body<FcmSuccessResponse>()
                PushResult.Success(body.name)
            }
            400 -> PushResult.Failure("잘못된 요청", retryable = false)
            401 -> PushResult.Failure("인증 실패 - 토큰 갱신 필요", retryable = true)
            404 -> PushResult.InvalidToken(request.deviceToken)
            429 -> PushResult.Failure("FCM 요청 한도 초과", retryable = true)
            500, 503 -> PushResult.Failure("FCM 서버 오류", retryable = true)
            else -> PushResult.Failure("Unknown: ${response.status}", retryable = false)
        }
    }

    override suspend fun sendBatch(requests: List<PushRequest>): List<PushResult> =
        requests.map { send(it) }  // FCM HTTP v1은 단건 전송, 병렬 처리로 보완

    private suspend fun getOrRefreshAccessToken(): String {
        val now = Instant.now()
        if (cachedAccessToken != null && now.isBefore(tokenExpiresAt.minusSeconds(60))) {
            return cachedAccessToken!!
        }

        // 서비스 계정 키로 JWT 생성 후 Google OAuth2 토큰 교환
        val serviceAccountKey = readServiceAccountKey(serviceAccountKeyPath)
        val jwt = buildGoogleJwt(serviceAccountKey)

        val tokenResponse = httpClient.post("https://oauth2.googleapis.com/token") {
            contentType(ContentType.Application.FormUrlEncoded)
            setBody("grant_type=urn:ietf:params:oauth:grant-type:jwt-bearer&assertion=$jwt")
        }

        val token = tokenResponse.body<GoogleTokenResponse>()
        cachedAccessToken = token.accessToken
        tokenExpiresAt = Instant.now().plusSeconds(token.expiresIn.toLong())
        return token.accessToken
    }

    private fun buildFcmMessage(request: PushRequest): Map<String, Any> = mapOf(
        "token" to request.deviceToken,
        "notification" to mapOf(
            "title" to request.title,
            "body" to request.body
        ),
        "android" to mapOf(
            "priority" to if (request.priority == PushPriority.HIGH) "high" else "normal",
            "notification" to mapOf("sound" to "default")
        ),
        "data" to request.data
    )

    private fun buildGoogleJwt(key: ServiceAccountKey): String {
        val now = Instant.now()
        val privateKey = loadRsaPrivateKey(key.privateKey)
        return Jwts.builder()
            .setIssuer(key.clientEmail)
            .setAudience("https://oauth2.googleapis.com/token")
            .setIssuedAt(Date.from(now))
            .setExpiration(Date.from(now.plusSeconds(3600)))
            .claim("scope", "https://www.googleapis.com/auth/firebase.messaging")
            .signWith(privateKey, SignatureAlgorithm.RS256)
            .compact()
    }
}

data class FcmSuccessResponse(val name: String)
data class GoogleTokenResponse(
    @JsonProperty("access_token") val accessToken: String,
    @JsonProperty("expires_in") val expiresIn: Int
)
```

**알림 큐 및 재시도/실패 처리 전략**

```kotlin
// notification-service/src/main/kotlin/com/maum/notification/queue/NotificationQueueService.kt

@Service
class NotificationQueueService(
    private val redisTemplate: RedisTemplate<String, String>,
    private val objectMapper: ObjectMapper,
) {
    companion object {
        const val QUEUE_KEY = "notification:queue"
        const val DEAD_LETTER_KEY = "notification:dead-letter"
        const val MAX_RETRY = 3
    }

    fun enqueue(logId: String) {
        redisTemplate.opsForList().leftPush(QUEUE_KEY, logId)
    }

    fun dequeue(): String? =
        redisTemplate.opsForList().rightPop(QUEUE_KEY)

    fun moveToDeadLetter(logId: String) {
        redisTemplate.opsForList().leftPush(DEAD_LETTER_KEY, logId)
    }
}

// notification-service/src/main/kotlin/com/maum/notification/worker/NotificationWorker.kt

@Component
class NotificationWorker(
    private val queueService: NotificationQueueService,
    private val notificationLogRepository: NotificationLogRepository,
    private val deviceTokenRepository: DeviceTokenRepository,
    private val apnsClient: ApnsClient,
    private val fcmHttpClient: FcmHttpClient,
) {
    companion object {
        private val logger = LoggerFactory.getLogger(NotificationWorker::class.java)
        private val RETRY_DELAYS = listOf(5L, 30L, 120L)  // 초 단위: 5s, 30s, 2m
    }

    @Scheduled(fixedDelay = 100)  // 100ms 폴링
    fun processQueue() {
        val logId = queueService.dequeue() ?: return
        val log = notificationLogRepository.findById(logId).orElse(null) ?: return

        val deviceToken = deviceTokenRepository.findById(log.deviceTokenId).orElse(null)
        if (deviceToken == null) {
            log.status = NotificationStatus.FAILED
            log.lastError = "DeviceToken 없음"
            notificationLogRepository.save(log)
            return
        }

        val request = PushRequest(
            deviceToken = deviceToken.token,
            platform = deviceToken.platform,
            title = log.title,
            body = log.body,
            data = log.payload?.let { objectMapper.readValue(it) } ?: emptyMap(),
            notificationType = log.notificationType,
            priority = if (log.notificationType == NotificationType.CALL) PushPriority.HIGH else PushPriority.NORMAL
        )

        val client = if (deviceToken.platform == DevicePlatform.IOS) apnsClient else fcmHttpClient

        runBlocking {
            when (val result = client.send(request)) {
                is PushResult.Success -> {
                    log.status = NotificationStatus.SENT
                    log.sentAt = LocalDateTime.now()
                    deviceToken.lastUsedAt = LocalDateTime.now()
                    deviceTokenRepository.save(deviceToken)
                }
                is PushResult.InvalidToken -> {
                    log.status = NotificationStatus.INVALID_TOKEN
                    deviceToken.tokenStatus = TokenStatus.INVALID
                    deviceTokenRepository.save(deviceToken)
                    logger.warn("무효 토큰 처리: userId=${deviceToken.userId}, tokenId=${deviceToken.id}")
                }
                is PushResult.Failure -> {
                    if (result.retryable && log.retryCount < NotificationQueueService.MAX_RETRY) {
                        val delay = RETRY_DELAYS.getOrElse(log.retryCount) { 120L }
                        log.retryCount++
                        log.lastError = result.error
                        // 지연 재시도: Redis ZADD (score = 재시도 시각)
                        scheduleRetry(logId, delay)
                    } else {
                        log.status = NotificationStatus.FAILED
                        log.failedAt = LocalDateTime.now()
                        log.lastError = result.error
                        queueService.moveToDeadLetter(logId)
                        logger.error("알림 최종 실패: logId=$logId, error=${result.error}")
                    }
                }
            }
        }

        notificationLogRepository.save(log)
    }

    private fun scheduleRetry(logId: String, delaySeconds: Long) {
        val score = Instant.now().plusSeconds(delaySeconds).epochSecond.toDouble()
        redisTemplate.opsForZSet().add("notification:retry", logId, score)
    }
}
```

