```kotlin
// 전환 플래그를 통한 점진적 전환 (Feature Toggle)
@Service
class PushDispatchService(
    private val apnsClient: ApnsClient,
    private val fcmHttpClient: FcmHttpClient,
    private val legacyFcmService: LegacyFcmService,   // 기존 SDK
    @Value("\${push.use-new-system:false}") private val useNewSystem: Boolean,
) {
    fun dispatch(userId: String, platform: DevicePlatform, request: PushRequest) {
        if (useNewSystem) {
            // 새 시스템 경로
            runBlocking { selectClient(platform).send(request) }
        } else {
            // 기존 Firebase Admin SDK 경로
            legacyFcmService.send(request)
        }
    }

    private fun selectClient(platform: DevicePlatform) =
        if (platform == DevicePlatform.IOS) apnsClient else fcmHttpClient
}
